begin; select plan(25);
select has_table('public','work_items','reusable owned work exists');
select has_table('public','confidential_reporter_identities','reporter identity is separated');
select has_table('public','move_in_workspaces','resident move-in workspace exists');
select has_table('public','report_snapshots','immutable as-of snapshots exist');
select has_table('public','evidence_guest_grants','scoped evidence room grants exist');
select has_function('public','authorize_evidence_guest_artifact',array['text','uuid','text','text'],'guest access is server authorized');
select ok(not has_table_privilege('authenticated','public.confidential_reporter_identities','SELECT'),'reporter identity is not exposed to browser roles');
select ok(has_table_privilege('authenticated','public.report_schedules','SELECT'),'authenticated reporting roles can read report schedules through RLS');
select ok(not has_function_privilege('anon','public.create_deduplicated_work_item(uuid,uuid,text,text,uuid,text,text,text,uuid,text,timestamp with time zone)','EXECUTE'),'anonymous callers cannot create internal work');
select ok(has_function_privilege('anon','public.authorize_evidence_guest_artifact(text,uuid,text,text)','EXECUTE'),'external artifact authorization is an explicit narrow API');
select ok(not has_function_privilege('anon','public.start_confidential_incident_intake(uuid,text,timestamp with time zone,boolean,text,text,text,text,uuid,jsonb,text,text)','EXECUTE'),'anonymous intake cannot bypass Turnstile Edge boundary');
select ok(not exists(select 1 from pg_class c join pg_namespace n on n.oid=c.relnamespace where n.nspname='public' and c.relname in('work_items','work_item_history','confidential_incident_intakes','confidential_incident_details','confidential_reporter_identities','move_in_workspaces','move_in_guest_grants','saved_report_definitions','report_snapshots','evidence_collections','evidence_guest_grants','evidence_guest_access_events') and not c.relrowsecurity),'all Phase 5 exposed tables enable RLS');

insert into public.organizations(id,name,slug,subscription_status) values('55000000-0000-4000-8000-000000000001','Phase 5 Org','phase5-org','active');
insert into public.facilities(id,organization_id,name,facility_type) values('55000000-0000-4000-8000-000000000011','55000000-0000-4000-8000-000000000001','Phase 5 Facility','PCH');
insert into auth.users(instance_id,id,aud,role,email,encrypted_password,email_confirmed_at,raw_app_meta_data,raw_user_meta_data,created_at,updated_at,confirmation_token,recovery_token,email_change_token_new,email_change,email_change_token_current,reauthentication_token,is_sso_user,is_anonymous) values('00000000-0000-0000-0000-000000000000','55000000-0000-4000-8000-000000000101','authenticated','authenticated','p5-admin@test.local','x',now(),'{}','{}',now(),now(),'','','','','','',false,false);
select set_config('app.privileged_write','on',true);
insert into public.profiles(id,organization_id,email,first_name,last_name,role,is_active) values('55000000-0000-4000-8000-000000000101','55000000-0000-4000-8000-000000000001','p5-admin@test.local','Phase','Admin','org_admin',true) on conflict(id) do update set organization_id=excluded.organization_id,role=excluded.role,is_active=true;
select set_config('app.privileged_write','off',true);
insert into public.residents(id,organization_id,facility_id,first_name,last_name,admission_date) values('55000000-0000-4000-8000-000000000201','55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011','Move','In',current_date);
insert into public.work_item_templates(id,organization_id,template_key,name,source_type,required_evidence_types,approval_required) values('55000000-0000-4000-8000-000000000301','55000000-0000-4000-8000-000000000001','incident.followup','Incident follow-up','incident',array['closure_document'],true);
create or replace function pg_temp.act_as(p_id uuid,p_role text default 'authenticated') returns void language plpgsql as $$begin reset role;perform set_config('request.jwt.claims',jsonb_build_object('sub',p_id,'role',p_role,'aal','aal2','iat',extract(epoch from now())::bigint)::text,true);if p_role='service_role' then set local role service_role;else set local role authenticated;end if;end$$;
create temporary table p5_ids(key text primary key,id uuid,value text) on commit drop;grant all on p5_ids to authenticated,service_role;
select pg_temp.act_as('55000000-0000-4000-8000-000000000101');
insert into p5_ids(key,id) values('work',public.create_deduplicated_work_item('55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011','incident.followup','incident','55000000-0000-4000-8000-000000000901','incident:901','Investigate incident','Complete investigation','55000000-0000-4000-8000-000000000101','high',now()+interval '1 day'));
select is(public.create_deduplicated_work_item('55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011','incident.followup','incident','55000000-0000-4000-8000-000000000901','incident:901','Investigate incident','Complete investigation','55000000-0000-4000-8000-000000000101','high',now()+interval '1 day'),(select id from p5_ids where key='work'),'configured source creates one deduplicated action');
select throws_ok($$select public.transition_work_item((select id from p5_ids where key='work'),'closed','Investigation complete')$$,'55000',null,'closure fails without configured evidence');
reset role;insert into public.work_item_evidence(organization_id,facility_id,work_item_id,evidence_type,linked_record_type,linked_record_id,submitted_by) values('55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011',(select id from p5_ids where key='work'),'closure_document','incident','55000000-0000-4000-8000-000000000901','55000000-0000-4000-8000-000000000101');
select pg_temp.act_as('55000000-0000-4000-8000-000000000101');select lives_ok($$select public.transition_work_item((select id from p5_ids where key='work'),'pending_approval','Evidence submitted for manager review')$$,'evidence-backed work can enter approval');
select lives_ok($$select public.approve_work_item((select id from p5_ids where key='work'),'Evidence reviewed and closure approved')$$,'approval-required work closes through explicit approval');
select is((select count(*)::integer from public.work_item_history where work_item_id=(select id from p5_ids where key='work')),3,'work history retains creation, submission, and approval');
reset role;
insert into public.confidential_incident_intakes(id,organization_id,facility_id,report_type,severity,reporter_mode,public_summary,resume_secret_sha256,confirmation_token_sha256) values('55000000-0000-4000-8000-000000000401','55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011','near_miss','high','anonymous','Medication near miss',repeat('a',64),repeat('b',64));
insert into public.confidential_incident_details(intake_id,organization_id,resident_id,narrative) values('55000000-0000-4000-8000-000000000401','55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000201','Protected resident and witness narrative');
insert into public.confidential_reporter_identities(intake_id,organization_id,encrypted_contact) values('55000000-0000-4000-8000-000000000401','55000000-0000-4000-8000-000000000001','{"ciphertext":"opaque"}');
select is((select count(*)::integer from public.confidential_incident_details where intake_id='55000000-0000-4000-8000-000000000401'),1,'confidential detail is linked without broad task exposure');
insert into public.move_in_templates(id,organization_id,name,version,definition) values('55000000-0000-4000-8000-000000000501','55000000-0000-4000-8000-000000000001','Standard move-in',1,'{"tasks":["documents","signature"]}');
insert into public.move_in_workspaces(id,organization_id,facility_id,resident_id,template_id,target_move_in_date,created_by) values('55000000-0000-4000-8000-000000000502','55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011','55000000-0000-4000-8000-000000000201','55000000-0000-4000-8000-000000000501',current_date+7,'55000000-0000-4000-8000-000000000101');
insert into public.move_in_tasks(id,organization_id,facility_id,workspace_id,task_key,title,requires_signature) values('55000000-0000-4000-8000-000000000503','55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011','55000000-0000-4000-8000-000000000502','signature','Sign admission agreement',true);
insert into public.move_in_guest_grants(organization_id,facility_id,workspace_id,resident_id,token_sha256,guest_label,allowed_task_ids,expires_at,terms_version) values('55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011','55000000-0000-4000-8000-000000000502','55000000-0000-4000-8000-000000000201',repeat('c',64),'Designated person',array['55000000-0000-4000-8000-000000000503'::uuid],now()+interval '7 days','v1');
select is((select cardinality(allowed_task_ids) from public.move_in_guest_grants limit 1),1,'move-in guest scope contains only selected resident tasks');

insert into public.saved_report_definitions(id,organization_id,name,report_type) values('55000000-0000-4000-8000-000000000601','55000000-0000-4000-8000-000000000001','Compliance as-of','compliance');
insert into public.saved_report_versions(id,report_definition_id,organization_id,version_number,filters,columns,configuration_sha256,state,published_at) values('55000000-0000-4000-8000-000000000602','55000000-0000-4000-8000-000000000601','55000000-0000-4000-8000-000000000001',1,'{"facilityId":"55000000-0000-4000-8000-000000000011"}','["status","dueDate"]',repeat('d',64),'published',now());update public.saved_report_definitions set current_version_id='55000000-0000-4000-8000-000000000602' where id='55000000-0000-4000-8000-000000000601';
select pg_temp.act_as('00000000-0000-0000-0000-000000000000','service_role');insert into p5_ids(key,id) values('snapshot',public.record_report_snapshot('55000000-0000-4000-8000-000000000602','55000000-0000-4000-8000-000000000011','2026-07-01T00:00:00Z','{"auditMaxId":"100"}','{"employees":["e1","e2"]}','{"employees":2}','{"compliant":2}','reconciled','{}'));
select is(public.record_report_snapshot('55000000-0000-4000-8000-000000000602','55000000-0000-4000-8000-000000000011','2026-07-01T00:00:00Z','{"auditMaxId":"100"}','{"employees":["e1","e2"]}','{"employees":2}','{"compliant":2}','reconciled','{}'),(select id from p5_ids where key='snapshot'),'same report version and as-of point returns canonical snapshot');
select is((select reconciliation_status from public.report_snapshots where id=(select id from p5_ids where key='snapshot')),'reconciled','snapshot records source reconciliation');
insert into public.report_snapshot_artifacts(id,organization_id,facility_id,snapshot_id,artifact_type,storage_bucket,storage_path,content_sha256,byte_size,manifest) values('55000000-0000-4000-8000-000000000603','55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011',(select id from p5_ids where key='snapshot'),'pdf','binder-exports','phase5/report.pdf',repeat('e',64),1000,'{"rows":2}');
insert into public.evidence_collections(id,organization_id,facility_id,name,purpose,status,terms_version,published_at) values('55000000-0000-4000-8000-000000000701','55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011','Survey 2026','State survey','published','v1',now());
insert into public.evidence_collection_artifacts(id,organization_id,facility_id,collection_id,snapshot_artifact_id,display_name) values('55000000-0000-4000-8000-000000000702','55000000-0000-4000-8000-000000000001','55000000-0000-4000-8000-000000000011','55000000-0000-4000-8000-000000000701','55000000-0000-4000-8000-000000000603','Compliance report');
select pg_temp.act_as('55000000-0000-4000-8000-000000000101');insert into p5_ids(key,id,value) select 'grant',(x->>'grantId')::uuid,x->>'token' from public.issue_evidence_guest_grant('55000000-0000-4000-8000-000000000701','External auditor',repeat('f',64),array['55000000-0000-4000-8000-000000000702'::uuid],now()+interval '1 day',false)x;
reset role;update public.evidence_guest_grants set accepted_at=now() where id=(select id from p5_ids where key='grant');
select is((public.authorize_evidence_guest_artifact((select value from p5_ids where key='grant'),'55000000-0000-4000-8000-000000000702','view',repeat('1',64))->>'authorized')::boolean,true,'accepted scoped guest grant authorizes selected immutable artifact');
update public.evidence_guest_grants set revoked_at=now() where id=(select id from p5_ids where key='grant');
select is((public.authorize_evidence_guest_artifact((select value from p5_ids where key='grant'),'55000000-0000-4000-8000-000000000702','view',repeat('1',64))->>'authorized')::boolean,false,'revocation immediately fails closed');
select is((select count(*)::integer from public.evidence_guest_access_events where guest_grant_id=(select id from p5_ids where key='grant')),2,'successful and denied external access are attributable');
select throws_ok($$update public.report_snapshots set row_counts='{"employees":3}' where id=(select id from p5_ids where key='snapshot')$$,'55000',null,'historical snapshot is immutable');
select * from finish();rollback;
